  1	import * as React from 'react';
  2	import Helmet from 'react-helmet';
  3	import {
  4	  Page,
  5	  PageSection,
  6	  Title,
  7	  Card,
  8	  CardTitle,
  9	  CardBody,
 10	  TextContent,
 11	  Text,
 12	  Toolbar,
 13	  ToolbarContent,
 14	  ToolbarFilter,
 15	  ToolbarItem,
 16	  Badge,
 17	  Select,
 18	  SelectList,
 19	  SelectOption,
 20	  MenuToggle,
 21	} from '@patternfly/react-core';
 22	import {
 23	  useK8sWatchResource,
 24	  useAccessReview,
 25	  K8sVerb,
 26	} from '@openshift-console/dynamic-plugin-sdk';
 27	import {
 28	  DagreLayout,
 29	  DefaultEdge,
 30	  DefaultNode,
 31	  ModelKind,
 32	  GraphComponent,
 33	  NodeShape,
 34	  TopologyControlBar,
 35	  TopologyView,
 36	  Visualization,
 37	  VisualizationProvider,
 38	  VisualizationSurface,
 39	  withPanZoom,
 40	  withSelection,
 41	  createTopologyControlButtons,
 42	  defaultControlButtonsOptions,
 43	  LabelPosition,
 44	  EdgeStyle,
 45	  EdgeAnimationSpeed,
 46	  withContextMenu,
 47	  ContextMenuItem,
 48	  action,
 49	  DefaultGroup,
 50	} from '@patternfly/react-topology';
 51	import { useTranslation } from 'react-i18next';
 52	
 53	import { CubesIcon, CloudUploadAltIcon, TopologyIcon, RouteIcon } from '@patternfly/react-icons';
 54	
 55	import * as dot from 'graphlib-dot';
 56	import './kuadrant.css';
 57	import NoPermissionsView from './NoPermissionsView';
 58	
 59	interface GVK {
 60	  group: string;
 61	  version: string;
 62	  kind: string;
 63	}
 64	let dynamicResourceGVKMapping: Record<string, GVK> = {};
 65	const resourceHints: Record<string, string> = {
 66	  Gateway: 'gateway.networking.k8s.io',
 67	  DNSRecord: 'kuadrant.io',
 68	};
 69	
 70	// Fetch the config.js file dynamically at runtime
 71	// Normally served from <cluster-host>/api/plugins/kuadrant-console/config.js
 72	const fetchConfig = async () => {
 73	  const defaultConfig = {
 74	    TOPOLOGY_CONFIGMAP_NAME: 'topology',
 75	    TOPOLOGY_CONFIGMAP_NAMESPACE: 'kuadrant-system',
 76	  };
 77	
 78	  try {
 79	    const response = await fetch('/api/plugins/kuadrant-console-plugin/config.js');
 80	    if (!response.ok) {
 81	      if (response.status === 404) {
 82	        console.warn('config.js not found (running locally perhaps). Falling back to defaults.');
 83	      } else {
 84	        throw new Error(`Failed to fetch config.js: ${response.statusText}`);
 85	      }
 86	      return defaultConfig; // Fallback on 404
 87	    }
 88	
 89	    const script = await response.text();
 90	
 91	    const configScript = document.createElement('script');
 92	    configScript.innerHTML = script;
 93	    document.head.appendChild(configScript);
 94	
 95	    return (window as any).kuadrant_config || defaultConfig;
 96	  } catch (error) {
 97	    console.error('Error loading config.js:', error);
 98	    return defaultConfig;
 99	  }
100	};
101	
102	export const kindToAbbr = (kind: string) => {
103	  return (kind.replace(/[^A-Z]/g, '') || kind.toUpperCase()).slice(0, 4);
104	};
105	
106	// List of resource types to show by default in the filter toolbar.
107	// Only these kinds will be shown in the initial render if they exist in the parsed DOTfile
108	const showByDefault = new Set([
109	  'AuthPolicy',
110	  'Authorino',
111	  'ConfigMap',
112	  'ConsolePlugin',
113	  'DNSPolicy',
114	  'Gateway',
115	  'HTTPRoute',
116	  'HTTPRouteRule',
117	  'Kuadrant',
118	  'Limitador',
119	  'Listener',
120	  'RateLimitPolicy',
121	  'TLSPolicy',
122	]);
123	
124	// Convert DOT graph to PatternFly node/edge models
125	const parseDotToModel = (dotString: string): { nodes: any[]; edges: any[] } => {
126	  try {
127	    const graph = dot.read(dotString);
128	    const nodes: any[] = [];
129	    const edges: any[] = [];
130	    const groups: any[] = [];
131	    const connectedNodeIds = new Set<string>();
132	
133	    const shapeMapping: { [key: string]: NodeShape } = {
134	      Gateway: NodeShape.rect,
135	      HTTPRoute: NodeShape.rect,
136	      TLSPolicy: NodeShape.rect,
137	      DNSPolicy: NodeShape.rect,
138	      AuthPolicy: NodeShape.rect,
139	      RateLimitPolicy: NodeShape.rect,
140	      ConfigMap: NodeShape.ellipse,
141	      Listener: NodeShape.rect,
142	      Kuadrant: NodeShape.ellipse,
143	    };
144	
145	    // kinds for unassociated policies - these will be grouped
146	    const unassociatedPolicies = new Set([
147	      'TLSPolicy',
148	      'DNSPolicy',
149	      'AuthPolicy',
150	      'RateLimitPolicy',
151	    ]);
152	
153	    // kinds for Kuadrant internals - these will be grouped also
154	    const kuadrantInternals = new Set([
155	      'ConfigMap',
156	      'Kuadrant',
157	      'Limitador',
158	      'Authorino',
159	      'ConsolePlugin',
160	    ]);
161	
162	    const addEdge = (source: string, target: string, type: string) => {
163	      edges.push({
164	        id: `edge-${source}-${target}`,
165	        type: 'edge',
166	        source,
167	        target,
168	        edgeStyle: type === 'policy' ? EdgeStyle.dashedMd : EdgeStyle.default,
169	        animationSpeed: type === 'policy' ? EdgeAnimationSpeed.medium : undefined,
170	        style: { strokeWidth: 2, stroke: '#393F44' },
171	      });
172	      connectedNodeIds.add(source);
173	      connectedNodeIds.add(target);
174	    };
175	
176	    // process edges: add each edge directly
177	    graph
178	      .edges()
179	      .forEach(({ v: sourceNodeId, w: targetNodeId }: { v: string; w: string }) =>
180	        addEdge(sourceNodeId, targetNodeId, 'default'),
181	      );
182	
183	    // create nodes
184	    graph.nodes().forEach((nodeId: string) => {
185	      const nodeData = graph.node(nodeId);
186	      const [resourceType, resourceName] = nodeData.label.split('\\n');
187	      nodes.push({
188	        id: nodeId,
189	        type: 'node',
190	        label: resourceName,
191	        resourceType,
192	        width: 120,
193	        height: 65,
194	        labelPosition: LabelPosition.bottom,
195	        shape: shapeMapping[resourceType] || NodeShape.rect,
196	        data: {
197	          label: resourceName,
198	          type: resourceType,
199	          badge: kindToAbbr(resourceType),
200	          badgeColor: '#2b9af3',
201	        },
202	      });
203	    });
204	
205	    const addGroup = (id: string, children: any[], label: string) => {
206	      groups.push({
207	        id,
208	        children: children.map((node) => node.id),
209	        type: 'group',
210	        group: true,
211	        label,
212	        style: { padding: 40 },
213	      });
214	    };
215	
216	    // Group unassociated policies
217	    const unassociatedPolicyNodes = nodes.filter(
218	      (node) => !connectedNodeIds.has(node.id) && unassociatedPolicies.has(node.resourceType),
219	    );
220	    if (unassociatedPolicyNodes.length) {
221	      addGroup('group-unattached', unassociatedPolicyNodes, 'Unattached Policies');
222	    }
223	
224	    // Group Kuadrant internals
225	    const kuadrantInternalNodes = nodes.filter((node) => kuadrantInternals.has(node.resourceType));
226	    if (kuadrantInternalNodes.length) {
227	      addGroup('group-kuadrant-internals', kuadrantInternalNodes, 'Kuadrant Internals');
228	    }
229	
230	    // Filter out any remaining edges with missing nodes
231	    const nodeIds = new Set(nodes.map((node) => node.id));
232	    const validEdges = edges.filter(
233	      ({ source, target }) => nodeIds.has(source) && nodeIds.has(target),
234	    );
235	
236	    return { nodes: [...nodes, ...groups], edges: validEdges };
237	  } catch (error) {
238	    console.error('Error parsing DOT string:', error);
239	    throw error;
240	  }
241	};
242	
243	// Custom node renderer
244	const CustomNode: React.FC<any> = ({
245	  element,
246	  onSelect,
247	  selected,
248	  onContextMenu,
249	  contextMenuOpen,
250	}) => {
251	  // Disable the context menu for these 'meta-kinds'
252	  const disabledContextMenuTypes = ['GatewayClass', 'HTTPRouteRule', 'Listener'];
253	  const data = element.getData();
254	  const { type, badge, badgeColor } = data;
255	
256	  const isPolicyNode = ['TLSPolicy', 'DNSPolicy', 'AuthPolicy', 'RateLimitPolicy'].includes(type);
257	
258	  let IconComponent;
259	  switch (type) {
260	    case 'Gateway':
261	      IconComponent = CubesIcon;
262	      break;
263	    case 'HTTPRoute':
264	      IconComponent = RouteIcon;
265	      break;
266	    case 'TLSPolicy':
267	    case 'DNSPolicy':
268	      IconComponent = CloudUploadAltIcon;
269	      break;
270	    case 'ConfigMap':
271	    case 'Listener':
272	      IconComponent = TopologyIcon;
273	      break;
274	    case 'GatewayClass':
275	      IconComponent = CubesIcon;
276	      break;
277	    case 'HttpRouteRule':
278	      IconComponent = RouteIcon;
279	      break;
280	    default:
281	      IconComponent = TopologyIcon;
282	      break;
283	  }
284	
285	  const iconSize = 35;
286	  const paddingTop = 5;
287	  const paddingBottom = 15;
288	  const nodeHeight = element.getBounds().height;
289	  const nodeWidth = element.getBounds().width;
290	
291	  return (
292	    <DefaultNode
293	      element={element}
294	      showStatusDecorator
295	      badge={badge}
296	      badgeColor={badgeColor}
297	      badgeTextColor="#fff"
298	      onSelect={onSelect}
299	      selected={selected}
300	      className={isPolicyNode ? 'policy-node' : ''}
301	      // Disable context menu for specified types
302	      onContextMenu={!disabledContextMenuTypes.includes(type) ? onContextMenu : undefined}
303	      contextMenuOpen={!disabledContextMenuTypes.includes(type) && contextMenuOpen}
304	    >
305	      <g transform={`translate(${nodeWidth / 2}, ${paddingTop})`}>
306	        <foreignObject width={iconSize} height={iconSize} x={-iconSize / 2}>
307	          <IconComponent
308	            style={{ color: '#393F44', width: `${iconSize}px`, height: `${iconSize}px` }}
309	          />
310	        </foreignObject>
311	      </g>
312	      <g transform={`translate(${nodeWidth / 2}, ${nodeHeight - paddingBottom})`}>
313	        <text
314	          className="kuadrant-topology-type-text"
315	          style={{
316	            fontWeight: 'bold',
317	            fontSize: '12px',
318	            fill: '#000',
319	            textAnchor: 'middle',
320	          }}
321	          dominantBaseline="central"
322	        >
323	          {type}
324	        </text>
325	      </g>
326	    </DefaultNode>
327	  );
328	};
329	
330	const goToResource = (resourceType: string, resourceName: string) => {
331	  let lookupType = resourceType;
332	  // special case - Listener should go to associated Gateway
333	  if (resourceType === 'Listener') {
334	    lookupType = 'Gateway';
335	  }
336	  const finalGVK = dynamicResourceGVKMapping[lookupType];
337	  if (!finalGVK) {
338	    console.error(`GVK mapping not found for resource type: ${lookupType}`);
339	    return;
340	  }
341	  const [namespace, name] = resourceName.includes('/')
342	    ? resourceName.split('/')
343	    : [null, resourceName];
344	
345	  const url = namespace
346	    ? `/k8s/ns/${namespace}/${finalGVK.group}~${finalGVK.version}~${finalGVK.kind}/${name}`
347	    : `/k8s/cluster/${finalGVK.group}~${finalGVK.version}~${finalGVK.kind}/${name}`;
348	
349	  window.location.href = url;
350	};
351	
352	const customLayoutFactory = (type: string, graph: any): any => {
353	  return new DagreLayout(graph, {
354	    rankdir: 'TB',
355	    nodesep: 20,
356	    ranksep: 0,
357	    nodeDistance: 80,
358	  });
359	};
360	
361	interface PolicyConfig {
362	  key: string;
363	  displayName: string;
364	}
365	const ResourcePolicyMap: Record<string, PolicyConfig[]> = {
366	  Gateway: [
367	    { key: 'AuthPolicy', displayName: 'Create AuthPolicy' },
368	    { key: 'DNSPolicy', displayName: 'Create DNSPolicy' },
369	    { key: 'RateLimitPolicy', displayName: 'Create RateLimitPolicy' },
370	    { key: 'TLSPolicy', displayName: 'Create TLSPolicy' },
371	  ],
372	  HTTPRoute: [
373	    { key: 'AuthPolicy', displayName: 'Create AuthPolicy' },
374	    { key: 'RateLimitPolicy', displayName: 'Create RateLimitPolicy' },
375	  ],
376	};
377	const navigateToCreatePolicy = (policyType: string) => {
378	  const resource = dynamicResourceGVKMapping[policyType];
379	  if (!resource) {
380	    console.error(`GVK mapping not found for policy type: ${policyType}`);
381	    return;
382	  }
383	  const url = `/k8s/ns/default/${resource.group}~${resource.version}~${resource.kind}/~new`;
384	  window.location.href = url;
385	};
386	
387	const getPolicyConfigsForResource = (resourceType: string): PolicyConfig[] =>
388	  (ResourcePolicyMap[resourceType] || []).filter((policy) => dynamicResourceGVKMapping[policy.key]);
389	
390	const customComponentFactory = (kind: ModelKind, type: string) => {
391	  const contextMenuItem = (resourceType: string, resourceName: string) => {
392	    const policyConfigs = getPolicyConfigsForResource(resourceType);
393	    return (
394	      <>
395	        <ContextMenuItem
396	          key="go-to-resource"
397	          onClick={() => goToResource(resourceType, resourceName)}
398	        >
399	          Go to Resource
400	        </ContextMenuItem>
401	        {policyConfigs.map((policy) => (
402	          <ContextMenuItem
403	            key={`create-${policy.key.toLowerCase()}`}
404	            onClick={() => navigateToCreatePolicy(policy.key)}
405	          >
406	            {policy.displayName}
407	          </ContextMenuItem>
408	        ))}
409	      </>
410	    );
411	  };
412	
413	  const contextMenu = (element: any) => {
414	    const resourceType = element.getData().type;
415	    const resourceName = element.getLabel();
416	    return [contextMenuItem(resourceType, resourceName)];
417	  };
418	
419	  switch (type) {
420	    case 'group':
421	      return DefaultGroup;
422	    default:
423	      switch (kind) {
424	        case ModelKind.graph:
425	          return withPanZoom()(GraphComponent);
426	        case ModelKind.node:
427	          return withContextMenu(contextMenu)(CustomNode);
428	        case ModelKind.edge:
429	          return withSelection()(DefaultEdge);
430	        default:
431	          return undefined;
432	      }
433	  }
434	};
435	
436	const PolicyTopologyPage: React.FC = () => {
437	  const [config, setConfig] = React.useState<any | null>(null);
438	  const [parseError, setParseError] = React.useState<string | null>(null);
439	  // dynamically generated list of all resource types from the parsed DOT file
440	  const [allResourceTypes, setAllResourceTypes] = React.useState<string[]>([]);
441	  // Resource filter state. On initial render, show only resources in showByDefault
442	  const [selectedResourceTypes, setSelectedResourceTypes] = React.useState<string[]>([]);
443	  const [isResourceFilterOpen, setIsResourceFilterOpen] = React.useState(false);
444	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
445	
446	  const onResourceSelect = (
447	    _event: React.MouseEvent | React.ChangeEvent | undefined,
448	    selection: string,
449	  ) => {
450	    // Toggle selection: remove if already selected, add if not
451	    if (selectedResourceTypes.includes(selection)) {
452	      setSelectedResourceTypes(selectedResourceTypes.filter((r) => r !== selection));
453	    } else {
454	      setSelectedResourceTypes([...selectedResourceTypes, selection]);
455	    }
456	  };
457	
458	  const onDeleteResourceFilter = (_category: string, chip: string) => {
459	    if (chip) {
460	      setSelectedResourceTypes(selectedResourceTypes.filter((r) => r !== chip));
461	    }
462	  };
463	
464	  const onDeleteResourceGroup = (_category: string) => {
465	    setSelectedResourceTypes([]);
466	  };
467	
468	  const clearAllFilters = () => {
469	    setSelectedResourceTypes([]);
470	  };
471	
472	  // Fetch configuration on mount
473	  React.useEffect(() => {
474	    const loadConfig = async () => {
475	      try {
476	        const configData = await fetchConfig();
477	        setConfig(configData);
478	      } catch (error) {
479	        console.error('Error loading config.js:', error);
480	        setParseError('Failed to load configuration.');
481	      }
482	    };
483	    loadConfig();
484	  }, []);
485	
486	  React.useEffect(() => {
487	    getGroupVersionKindForKind(resourceHints)
488	      .then((mapping) => {
489	        dynamicResourceGVKMapping = mapping; // used in goToResource
490	        console.debug('Prewarmed API resource mapping:', mapping);
491	      })
492	      .catch((err) => {
493	        console.error('Error prewarming API resource mapping:', err);
494	      });
495	  }, []);
496	
497	  // Watch the ConfigMap named "topology" in the namespace provided by the config.js
498	  const [configMap, loaded, loadError] = useK8sWatchResource<any>(
499	    config
500	      ? {
501	          groupVersionKind: {
502	            version: 'v1',
503	            kind: 'ConfigMap',
504	          },
505	          name: config.TOPOLOGY_CONFIGMAP_NAME,
506	          namespace: config.TOPOLOGY_CONFIGMAP_NAMESPACE,
507	        }
508	      : null, // Only watch if config is loaded
509	  );
510	
511	  const controllerRef = React.useRef<Visualization | null>(null);
512	
513	  React.useEffect(() => {
514	    if (!controllerRef.current) {
515	      const initialModel = {
516	        nodes: [],
517	        edges: [],
518	        graph: {
519	          id: 'g1',
520	          type: 'graph',
521	          layout: 'Dagre',
522	        },
523	      };
524	
525	      const visualization = new Visualization();
526	      visualization.registerLayoutFactory(customLayoutFactory);
527	      visualization.registerComponentFactory(customComponentFactory);
528	      visualization.fromModel(initialModel, false);
529	      controllerRef.current = visualization;
530	    }
531	
532	    // Cleanup on unmount
533	    return () => {
534	      controllerRef.current = null;
535	    };
536	  }, []);
537	
538	  // Handle data updates
539	  React.useEffect(() => {
540	    if (loaded && !loadError && configMap) {
541	      const dotString = configMap.data?.topology || '';
542	      if (dotString) {
543	        try {
544	          const { nodes, edges } = parseDotToModel(dotString);
545	          setParseError(null);
546	
547	          // Separate group nodes from normal nodes
548	          const groupNodes = nodes.filter((n) => n.type === 'group');
549	          const normalNodes = nodes.filter((n) => n.type !== 'group');
550	
551	          // Dynamically generate the list of resource types
552	          const uniqueTypes = Array.from(
553	            new Set(normalNodes.map((node) => node.resourceType)),
554	          ).sort();
555	          setAllResourceTypes(uniqueTypes);
556	
557	          // If the user has not yet set any filter, default to those in the showByDefault set
558	          let newSelected = selectedResourceTypes.filter((r) => uniqueTypes.includes(r));
559	          if (selectedResourceTypes.length === 0) {
560	            newSelected = uniqueTypes.filter((t) => showByDefault.has(t));
561	            setSelectedResourceTypes(newSelected);
562	          }
563	
564	          // Filter nodes by the selected resource types
565	          const filteredNormalNodes = normalNodes.filter((n) =>
566	            newSelected.includes(n.resourceType),
567	          );
568	
569	          // For each group, only keep children that are in the filtered nodes
570	          const keptNormalNodeIds = new Set(filteredNormalNodes.map((n) => n.id));
571	          const updatedGroups = groupNodes.map((g) => {
572	            const validChildren = g.children?.filter((childId: string) =>
573	              keptNormalNodeIds.has(childId),
574	            );
575	            return {
576	              ...g,
577	              children: validChildren,
578	            };
579	          });
580	          const filteredGroups = updatedGroups.filter((g) => g.children?.length > 0);
581	
582	          const finalNodes = [...filteredNormalNodes, ...filteredGroups];
583	
584	          // Filter edges to include only those connecting valid node IDs
585	          const validNodeIds = new Set(finalNodes.map((n) => n.id));
586	          const filteredEdges = edges.filter(
587	            (e) => validNodeIds.has(e.source) && validNodeIds.has(e.target),
588	          );
589	
590	          if (controllerRef.current) {
591	            const newModel = {
592	              nodes: finalNodes,
593	              edges: filteredEdges,
594	              graph: {
595	                id: 'g1',
596	                type: 'graph',
597	                layout: 'Dagre',
598	              },
599	            };
600	
601	            controllerRef.current.fromModel(newModel, false);
602	            controllerRef.current.getGraph().layout();
603	            controllerRef.current.getGraph().fit(80);
604	          }
605	        } catch (error) {
606	          setParseError('Failed to parse topology data.');
607	          console.error(error, dotString);
608	        }
609	      }
610	    } else if (loadError) {
611	      setParseError('Failed to load topology data.');
612	    }
613	  }, [configMap, loaded, loadError, selectedResourceTypes]);
614	
615	  const accessReviewProps = React.useMemo(() => {
616	    return config
617	      ? {
618	          group: '',
619	          resource: 'ConfigMap',
620	          verb: 'read' as K8sVerb,
621	          namespace: config.TOPOLOGY_CONFIGMAP_NAMESPACE,
622	          name: config.TOPOLOGY_CONFIGMAP_NAME,
623	        }
624	      : {
625	          // fallback
626	          group: '',
627	          resource: '',
628	          verb: 'read' as K8sVerb,
629	          namespace: '',
630	          name: '',
631	        };
632	  }, [config]);
633	
634	  const [canReadTopology, isLoadingPermissions] = useAccessReview(accessReviewProps);
635	
636	  if (!config) {
637	    return <div>{t('Loading configuration...')}</div>;
638	  }
639	
640	  if (isLoadingPermissions) {
641	    return <div>{t('Loading Permissions...')}</div>;
642	  }
643	
644	  if (!canReadTopology) {
645	    return (
646	      <NoPermissionsView
647	        primaryMessage={t('You do not have permission to view Policy Topology')}
648	        secondaryMessage={
649	          <>
650	            {t('Specifically, you do not have permission to read the ConfigMap ')}
651	            <strong>{config.TOPOLOGY_CONFIGMAP_NAME}</strong> {t('in the namespace ')}
652	            <strong>{config.TOPOLOGY_CONFIGMAP_NAMESPACE}</strong>
653	          </>
654	        }
655	      />
656	    );
657	  }
658	
659	  const controller = controllerRef.current;
660	
661	  return (
662	    <>
663	      <Helmet>
664	        <title>{t('Policy Topology')}</title>
665	      </Helmet>
666	      <Page>
667	        <PageSection variant="light">
668	          <Title headingLevel="h1">{t('Policy Topology')}</Title>
669	        </PageSection>
670	        <PageSection className="policy-topology-section">
671	          <Card>
672	            <CardTitle>{t('Topology View')}</CardTitle>
673	            <CardBody>
674	              <TextContent>
675	                <Text component="p" className="pf-u-mb-md">
676	                  {t(
677	                    'This view visualizes the relationships and interactions between different resources within your cluster related to Kuadrant, allowing you to explore connections between Gateways, HTTPRoutes and Kuadrant Policies.',
678	                  )}
679	                </Text>
680	              </TextContent>
681	              <Toolbar
682	                id="resource-filter-toolbar"
683	                className="pf-m-toggle-group-container"
684	                collapseListedFiltersBreakpoint="xl"
685	                clearAllFilters={clearAllFilters}
686	                clearFiltersButtonText={t('Reset Filters')}
687	              >
688	                <ToolbarContent>
689	                  <ToolbarItem variant="chip-group">
