781	/**
782	 * Retrieves a mapping from Kubernetes resource kinds to their Group/Version/Kind (GVK)
783	 * by querying both core API resources and aggregated API discovery.
784	 *
785	 * TODO: externalise this as a more general purpose helper for use elsewhere in the plugin
786	 * TODO: consider a contrib to https://github.com/openshift/dynamic-plugin-sdk/blob/main/packages/lib-utils/src/k8s/k8s-utils.ts
787	 *
788	 * This function accepts a resource hints object. If multiple API groups provide the same kind,
789	 * the one matching the hint (if provided) will be used.
790	 *
791	 * @param resourceHints - a mapping of resource kinds to the preferred API group.
792	 * Example:
793	 * {
794	 *   Gateway: 'gateway.networking.k8s.io',
795	 *   DNSRecord: 'kuadrant.io'
796	 * }
797	 *
798	 * @returns a Promise that resolves to an object mapping resource kinds to their GVK.
799	 */
800	export const getGroupVersionKindForKind = async (
801	  resourceHints: Record<string, string>,
802	): Promise<Record<string, GVK>> => {
803	  const mapping: Record<string, GVK> = {};
804	
805	  // Helper to provide resource hinting where there could be resource ambiguity (E.g. `dnsrecords.kuadrant.io` vs `dnsrecords.ingress.operator.openshift.io`)
806	  const updateMapping = (kind: string, group: string, version: string) => {
807	    if (resourceHints[kind]) {
808	      // Always override if the new group is the hinted group.
809	      if (group === resourceHints[kind]) {
810	        mapping[kind] = { group, version, kind };
811	      }
812	    } else if (!mapping[kind]) {
813	      mapping[kind] = { group, version, kind };
814	    }
815	  };
816	
817	  // fetch core API resources
818	  try {
819	    const coreResp = await fetch('/api/kubernetes/api/v1');
820	    if (!coreResp.ok) {
821	      throw new Error(`Error fetching /api/kubernetes/api/v1: ${coreResp.statusText}`);
822	    }
823	    const coreData = await coreResp.json();
824	    if (Array.isArray(coreData.resources)) {
825	      coreData.resources.forEach((res: any) => {
826	        if (res.kind && !res.name?.includes('/')) {
827	          // core API resources have an empty group and are v1
828	          updateMapping(res.kind, '', 'v1');
829	        }
830	      });
831	    }
832	  } catch (error) {
833	    console.error('Error fetching core API resources:', error);
834	  }
835	
836	  // aggregated API discovery data from /api/kubernetes/apis
837	  // https://github.com/kubernetes/enhancements/blob/master/keps/sig-api-machinery/3352-aggregated-discovery/README.md
838	  try {
839	    const aggregatedResp = await fetch('/api/kubernetes/apis', {
840	      headers: {
841	        Accept: 'application/json;g=apidiscovery.k8s.io;v=v2;as=APIGroupDiscoveryList',
842	      },
843	    });
844	    if (!aggregatedResp.ok) {
845	      throw new Error(`Error fetching aggregated discovery: ${aggregatedResp.statusText}`);
846	    }
847	    const aggregatedData = await aggregatedResp.json();
848	    if (Array.isArray(aggregatedData.items)) {
849	      aggregatedData.items.forEach((groupItem: any) => {
850	        const groupName = groupItem.metadata?.name;
851	        if (groupItem.versions && Array.isArray(groupItem.versions)) {
852	          groupItem.versions.forEach((versionData: any) => {
853	            const version = versionData.version;
854	            if (versionData.resources && Array.isArray(versionData.resources)) {
855	              versionData.resources.forEach((resource: any) => {
856	                const kind = resource.responseKind?.kind || resource.kind;
857	                const resourceName = resource.resource || resource.name;
858	                if (kind && resourceName && !resourceName.includes('/')) {
859	                  updateMapping(kind, groupName, version);
860	                }
861	              });
862	            }
863	          });
864	        }
865	      });
866	    }
867	  } catch (error) {
868	    console.error('Error fetching aggregated API discovery data:', error);
869	  }
870	
871	  return mapping;
872	};
