 58	
 59	interface GVK {
 60	  group: string;
 61	  version: string;
 62	  kind: string;
 63	}
 64	let dynamicResourceGVKMapping: Record<string, GVK> = {};
 65	const resourceHints: Record<string, string> = {
 66	  Gateway: 'gateway.networking.k8s.io',
 67	  DNSRecord: 'kuadrant.io',
 68	};
 69	
 70	// Fetch the config.js file dynamically at runtime
 71	// Normally served from <cluster-host>/api/plugins/kuadrant-console/config.js
 72	const fetchConfig = async () => {
 73	  const defaultConfig = {
 74	    TOPOLOGY_CONFIGMAP_NAME: 'topology',
 75	    TOPOLOGY_CONFIGMAP_NAMESPACE: 'kuadrant-system',
 76	  };
 77	
 78	  try {
 79	    const response = await fetch('/api/plugins/kuadrant-console-plugin/config.js');
 80	    if (!response.ok) {
 81	      if (response.status === 404) {
 82	        console.warn('config.js not found (running locally perhaps). Falling back to defaults.');
 83	      } else {
 84	        throw new Error(`Failed to fetch config.js: ${response.statusText}`);
 85	      }
 86	      return defaultConfig; // Fallback on 404
 87	    }
 88	
 89	    const script = await response.text();
 90	
 91	    const configScript = document.createElement('script');
 92	    configScript.innerHTML = script;
 93	    document.head.appendChild(configScript);
 94	
 95	    return (window as any).kuadrant_config || defaultConfig;
 96	  } catch (error) {
 97	    console.error('Error loading config.js:', error);
 98	    return defaultConfig;
 99	  }
100	};
101	
102	export const kindToAbbr = (kind: string) => {
103	  return (kind.replace(/[^A-Z]/g, '') || kind.toUpperCase()).slice(0, 4);
104	};
105	
106	// List of resource types to show by default in the filter toolbar.
107	// Only these kinds will be shown in the initial render if they exist in the parsed DOTfile
108	const showByDefault = new Set([
109	  'AuthPolicy',
110	  'Authorino',
111	  'ConfigMap',
112	  'ConsolePlugin',
113	  'DNSPolicy',
114	  'Gateway',
115	  'HTTPRoute',
116	  'HTTPRouteRule',
117	  'Kuadrant',
118	  'Limitador',
119	  'Listener',
120	  'RateLimitPolicy',
121	  'TLSPolicy',
122	]);
123	
124	// Convert DOT graph to PatternFly node/edge models
125	const parseDotToModel = (dotString: string): { nodes: any[]; edges: any[] } => {
126	  try {
127	    const graph = dot.read(dotString);
128	    const nodes: any[] = [];
129	    const edges: any[] = [];
130	    const groups: any[] = [];
131	    const connectedNodeIds = new Set<string>();
132	
133	    const shapeMapping: { [key: string]: NodeShape } = {
134	      Gateway: NodeShape.rect,
135	      HTTPRoute: NodeShape.rect,
136	      TLSPolicy: NodeShape.rect,
137	      DNSPolicy: NodeShape.rect,
138	      AuthPolicy: NodeShape.rect,
139	      RateLimitPolicy: NodeShape.rect,
140	      ConfigMap: NodeShape.ellipse,
141	      Listener: NodeShape.rect,
142	      Kuadrant: NodeShape.ellipse,
143	    };
144	
145	    // kinds for unassociated policies - these will be grouped
146	    const unassociatedPolicies = new Set([
147	      'TLSPolicy',
148	      'DNSPolicy',
149	      'AuthPolicy',
150	      'RateLimitPolicy',
151	    ]);
152	
153	    // kinds for Kuadrant internals - these will be grouped also
154	    const kuadrantInternals = new Set([
155	      'ConfigMap',
156	      'Kuadrant',
157	      'Limitador',
158	      'Authorino',
159	      'ConsolePlugin',
160	    ]);
161	
162	    const addEdge = (source: string, target: string, type: string) => {
163	      edges.push({
164	        id: `edge-${source}-${target}`,
165	        type: 'edge',
166	        source,
167	        target,
168	        edgeStyle: type === 'policy' ? EdgeStyle.dashedMd : EdgeStyle.default,
169	        animationSpeed: type === 'policy' ? EdgeAnimationSpeed.medium : undefined,
170	        style: { strokeWidth: 2, stroke: '#393F44' },
171	      });
172	      connectedNodeIds.add(source);
173	      connectedNodeIds.add(target);
174	    };
175	
176	    // process edges: add each edge directly
177	    graph
178	      .edges()
179	      .forEach(({ v: sourceNodeId, w: targetNodeId }: { v: string; w: string }) =>
180	        addEdge(sourceNodeId, targetNodeId, 'default'),
181	      );
182	
183	    // create nodes
184	    graph.nodes().forEach((nodeId: string) => {
185	      const nodeData = graph.node(nodeId);
186	      const [resourceType, resourceName] = nodeData.label.split('\\n');
187	      nodes.push({
188	        id: nodeId,
189	        type: 'node',
190	        label: resourceName,
191	        resourceType,
192	        width: 120,
193	        height: 65,
194	        labelPosition: LabelPosition.bottom,
195	        shape: shapeMapping[resourceType] || NodeShape.rect,
196	        data: {
197	          label: resourceName,
198	          type: resourceType,
199	          badge: kindToAbbr(resourceType),
200	          badgeColor: '#2b9af3',
201	        },
202	      });
203	    });
204	
205	    const addGroup = (id: string, children: any[], label: string) => {
206	      groups.push({
207	        id,
208	        children: children.map((node) => node.id),
209	        type: 'group',
210	        group: true,
211	        label,
212	        style: { padding: 40 },
213	      });
214	    };
215	
216	    // Group unassociated policies
217	    const unassociatedPolicyNodes = nodes.filter(
218	      (node) => !connectedNodeIds.has(node.id) && unassociatedPolicies.has(node.resourceType),
219	    );
220	    if (unassociatedPolicyNodes.length) {
221	      addGroup('group-unattached', unassociatedPolicyNodes, 'Unattached Policies');
222	    }
223	
224	    // Group Kuadrant internals
