230	    // Filter out any remaining edges with missing nodes
231	    const nodeIds = new Set(nodes.map((node) => node.id));
232	    const validEdges = edges.filter(
233	      ({ source, target }) => nodeIds.has(source) && nodeIds.has(target),
234	    );
235	
236	    return { nodes: [...nodes, ...groups], edges: validEdges };
237	  } catch (error) {
238	    console.error('Error parsing DOT string:', error);
239	    throw error;
240	  }
