124	// Convert DOT graph to PatternFly node/edge models
125	const parseDotToModel = (dotString: string): { nodes: any[]; edges: any[] } => {
126	  try {
127	    const graph = dot.read(dotString);
128	    const nodes: any[] = [];
129	    const edges: any[] = [];
130	    const groups: any[] = [];
131	    const connectedNodeIds = new Set<string>();
132	
133	    const shapeMapping: { [key: string]: NodeShape } = {
134	      Gateway: NodeShape.rect,
135	      HTTPRoute: NodeShape.rect,
136	      TLSPolicy: NodeShape.rect,
137	      DNSPolicy: NodeShape.rect,
138	      AuthPolicy: NodeShape.rect,
139	      RateLimitPolicy: NodeShape.rect,
140	      ConfigMap: NodeShape.ellipse,
141	      Listener: NodeShape.rect,
142	      Kuadrant: NodeShape.ellipse,
143	    };
144	
145	    // kinds for unassociated policies - these will be grouped
146	    const unassociatedPolicies = new Set([
147	      'TLSPolicy',
148	      'DNSPolicy',
149	      'AuthPolicy',
150	      'RateLimitPolicy',
151	    ]);
152	
153	    // kinds for Kuadrant internals - these will be grouped also
154	    const kuadrantInternals = new Set([
155	      'ConfigMap',
156	      'Kuadrant',
157	      'Limitador',
158	      'Authorino',
159	      'ConsolePlugin',
160	    ]);
161	
162	    const addEdge = (source: string, target: string, type: string) => {
163	      edges.push({
164	        id: `edge-${source}-${target}`,
165	        type: 'edge',
166	        source,
167	        target,
168	        edgeStyle: type === 'policy' ? EdgeStyle.dashedMd : EdgeStyle.default,
169	        animationSpeed: type === 'policy' ? EdgeAnimationSpeed.medium : undefined,
170	        style: { strokeWidth: 2, stroke: '#393F44' },
171	      });
172	      connectedNodeIds.add(source);
173	      connectedNodeIds.add(target);
174	    };
175	
176	    // process edges: add each edge directly
177	    graph
178	      .edges()
179	      .forEach(({ v: sourceNodeId, w: targetNodeId }: { v: string; w: string }) =>
180	        addEdge(sourceNodeId, targetNodeId, 'default'),
181	      );
182	
183	    // create nodes
184	    graph.nodes().forEach((nodeId: string) => {
185	      const nodeData = graph.node(nodeId);
186	      const [resourceType, resourceName] = nodeData.label.split('\\n');
187	      nodes.push({
188	        id: nodeId,
189	        type: 'node',
190	        label: resourceName,
191	        resourceType,
192	        width: 120,
193	        height: 65,
194	        labelPosition: LabelPosition.bottom,
195	        shape: shapeMapping[resourceType] || NodeShape.rect,
196	        data: {
197	          label: resourceName,
198	          type: resourceType,
199	          badge: kindToAbbr(resourceType),
200	          badgeColor: '#2b9af3',
201	        },
202	      });
203	    });
204	
205	    const addGroup = (id: string, children: any[], label: string) => {
206	      groups.push({
207	        id,
208	        children: children.map((node) => node.id),
209	        type: 'group',
210	        group: true,
211	        label,
212	        style: { padding: 40 },
213	      });
214	    };
215	
216	    // Group unassociated policies
217	    const unassociatedPolicyNodes = nodes.filter(
218	      (node) => !connectedNodeIds.has(node.id) && unassociatedPolicies.has(node.resourceType),
219	    );
220	    if (unassociatedPolicyNodes.length) {
221	      addGroup('group-unattached', unassociatedPolicyNodes, 'Unattached Policies');
222	    }
223	
224	    // Group Kuadrant internals
225	    const kuadrantInternalNodes = nodes.filter((node) => kuadrantInternals.has(node.resourceType));
226	    if (kuadrantInternalNodes.length) {
227	      addGroup('group-kuadrant-internals', kuadrantInternalNodes, 'Kuadrant Internals');
228	    }
229	
230	    // Filter out any remaining edges with missing nodes
231	    const nodeIds = new Set(nodes.map((node) => node.id));
232	    const validEdges = edges.filter(
233	      ({ source, target }) => nodeIds.has(source) && nodeIds.has(target),
234	    );
235	
236	    return { nodes: [...nodes, ...groups], edges: validEdges };
237	  } catch (error) {
238	    console.error('Error parsing DOT string:', error);
239	    throw error;
240	  }
241	};
