337	  if (!finalGVK) {
338	    console.error(`GVK mapping not found for resource type: ${lookupType}`);
339	    return;
340	  }
341	  const [namespace, name] = resourceName.includes('/')
342	    ? resourceName.split('/')
343	    : [null, resourceName];
344	
345	  const url = namespace
346	    ? `/k8s/ns/${namespace}/${finalGVK.group}~${finalGVK.version}~${finalGVK.kind}/${name}`
347	    : `/k8s/cluster/${finalGVK.group}~${finalGVK.version}~${finalGVK.kind}/${name}`;
