782	/**
783	 * Retrieves a mapping from Kubernetes resource kinds to their Group/Version/Kind (GVK)
784	 * by querying both core API resources and aggregated API discovery.
785	 *
786	 * TODO: externalise this as a more general purpose helper for use elsewhere in the plugin
787	 * TODO: consider a contrib to https://github.com/openshift/dynamic-plugin-sdk/blob/main/packages/lib-utils/src/k8s/k8s-utils.ts
788	 *
789	 * This function accepts a resource hints object. If multiple API groups provide the same kind,
790	 * the one matching the hint (if provided) will be used.
791	 *
792	 * @param resourceHints - a mapping of resource kinds to the preferred API group.
793	 * Example:
794	 * {
795	 *   Gateway: 'gateway.networking.k8s.io',
796	 *   DNSRecord: 'kuadrant.io'
797	 * }
798	 *
799	 * @returns a Promise that resolves to an object mapping resource kinds to their GVK.
800	 */
801	export const getGroupVersionKindForKind = async (
802	  resourceHints: Record<string, string>,
803	): Promise<Record<string, GVK>> => {
804	  const mapping: Record<string, GVK> = {};
805	
806	  // Helper to provide resource hinting where there could be resource ambiguity (E.g. `dnsrecords.kuadrant.io` vs `dnsrecords.ingress.operator.openshift.io`)
807	  const updateMapping = (kind: string, group: string, version: string) => {
808	    if (resourceHints[kind]) {
809	      // Always override if the new group is the hinted group.
810	      if (group === resourceHints[kind]) {
811	        mapping[kind] = { group, version, kind };
812	      }
813	    } else if (!mapping[kind]) {
814	      mapping[kind] = { group, version, kind };
815	    }
816	  };
817	
818	  // fetch core API resources
819	  try {
820	    const coreResp = await fetch('/api/kubernetes/api/v1');
821	    if (!coreResp.ok) {
822	      throw new Error(`Error fetching /api/kubernetes/api/v1: ${coreResp.statusText}`);
823	    }
824	    const coreData = await coreResp.json();
825	    if (Array.isArray(coreData.resources)) {
826	      coreData.resources.forEach((res: any) => {
827	        if (res.kind && !res.name?.includes('/')) {
828	          // core API resources have an empty group and are v1
829	          updateMapping(res.kind, '', 'v1');
830	        }
831	      });
832	    }
833	  } catch (error) {
834	    console.error('Error fetching core API resources:', error);
835	  }
836	
837	  // aggregated API discovery data from /api/kubernetes/apis
838	  // https://github.com/kubernetes/enhancements/blob/master/keps/sig-api-machinery/3352-aggregated-discovery/README.md
839	  try {
840	    const aggregatedResp = await fetch('/api/kubernetes/apis', {
841	      headers: {
842	        Accept: 'application/json;g=apidiscovery.k8s.io;v=v2;as=APIGroupDiscoveryList',
843	      },
844	    });
845	    if (!aggregatedResp.ok) {
846	      throw new Error(`Error fetching aggregated discovery: ${aggregatedResp.statusText}`);
847	    }
848	    const aggregatedData = await aggregatedResp.json();
849	    if (Array.isArray(aggregatedData.items)) {
850	      aggregatedData.items.forEach((groupItem: any) => {
851	        const groupName = groupItem.metadata?.name;
852	        if (groupItem.versions && Array.isArray(groupItem.versions)) {
853	          groupItem.versions.forEach((versionData: any) => {
854	            const version = versionData.version;
855	            if (versionData.resources && Array.isArray(versionData.resources)) {
856	              versionData.resources.forEach((resource: any) => {
857	                const kind = resource.responseKind?.kind || resource.kind;
858	                const resourceName = resource.resource || resource.name;
859	                if (kind && resourceName && !resourceName.includes('/')) {
860	                  updateMapping(kind, groupName, version);
861	                }
862	              });
863	            }
864	          });
865	        }
866	      });
867	    }
868	  } catch (error) {
869	    console.error('Error fetching aggregated API discovery data:', error);
870	  }
871	
872	  return mapping;
873	};
874	
875	export default PolicyTopologyPage;

