329	const goToResource = (resourceType: string, resourceName: string) => {
330	  let lookupType = resourceType;
331	  // special case - Listener should go to associated Gateway
332	  if (resourceType === 'Listener') {
333	    lookupType = 'Gateway';
334	  }
335	  const finalGVK = dynamicResourceGVKMapping[lookupType];
336	  if (!finalGVK) {
337	    console.error(`GVK mapping not found for resource type: ${lookupType}`);
338	    return;
339	  }
340	  const [namespace, name] = resourceName.includes('/')
341	    ? resourceName.split('/')
342	    : [null, resourceName];
343	
344	  const url = namespace
345	    ? `/k8s/ns/${namespace}/${finalGVK.group}~${finalGVK.version}~${finalGVK.kind}/${name}`
346	    : `/k8s/cluster/${finalGVK.group}~${finalGVK.version}~${finalGVK.kind}/${name}`;
