435	const PolicyTopologyPage: React.FC = () => {
436	  const [config, setConfig] = React.useState<any | null>(null);
437	  const [parseError, setParseError] = React.useState<string | null>(null);
438	  // dynamically generated list of all resource types from the parsed DOT file
439	  const [allResourceTypes, setAllResourceTypes] = React.useState<string[]>([]);
