474	    const loadConfig = async () => {
475	      try {
476	        const configData = await fetchConfig();
477	        setConfig(configData);
478	      } catch (error) {
479	        console.error('Error loading config.js:', error);
480	        setParseError('Failed to load configuration.');
481	      }
482	    };
483	    loadConfig();
484	  }, []);
485	
