779	/**
780	 * Retrieves a mapping from Kubernetes resource kinds to their Group/Version/Kind (GVK)
781	 * by querying both core API resources and aggregated API discovery.
782	 *
783	 * TODO: externalise this as a more general purpose helper for use elsewhere in the plugin
784	 * TODO: consider a contrib to https://github.com/openshift/dynamic-plugin-sdk/blob/main/packages/lib-utils/src/k8s/k8s-utils.ts
785	 *
786	 * This function accepts a resource hints object. If multiple API groups provide the same kind,
787	 * the one matching the hint (if provided) will be used.
788	 *
789	 * @param resourceHints - a mapping of resource kinds to the preferred API group.
790	 * Example:
791	 * {
792	 *   Gateway: 'gateway.networking.k8s.io',
793	 *   DNSRecord: 'kuadrant.io'
794	 * }
795	 *
796	 * @returns a Promise that resolves to an object mapping resource kinds to their GVK.
797	 */
798	export const getGroupVersionKindForKind = async (
799	  resourceHints: Record<string, string>,
800	): Promise<Record<string, GVK>> => {
801	  const mapping: Record<string, GVK> = {};
802	
803	  // Helper to provide resource hinting where there could be resource ambiguity (E.g. `dnsrecords.kuadrant.io` vs `dnsrecords.ingress.operator.openshift.io`)
804	  const updateMapping = (kind: string, group: string, version: string) => {
805	    if (resourceHints[kind]) {
806	      // Always override if the new group is the hinted group.
807	      if (group === resourceHints[kind]) {
808	        mapping[kind] = { group, version, kind };
809	      }
810	    } else if (!mapping[kind]) {
811	      mapping[kind] = { group, version, kind };
812	    }
813	  };
814	
815	  // fetch core API resources
816	  try {
817	    const coreResp = await fetch('/api/kubernetes/api/v1');
818	    if (!coreResp.ok) {
819	      throw new Error(`Error fetching /api/kubernetes/api/v1: ${coreResp.statusText}`);
820	    }
821	    const coreData = await coreResp.json();
822	    if (Array.isArray(coreData.resources)) {
823	      coreData.resources.forEach((res: any) => {
824	        if (res.kind && !res.name?.includes('/')) {
825	          // core API resources have an empty group and are v1
826	          updateMapping(res.kind, '', 'v1');
827	        }
828	      });
829	    }
830	  } catch (error) {
831	    console.error('Error fetching core API resources:', error);
832	  }
833	
834	  // aggregated API discovery data from /api/kubernetes/apis
835	  // https://github.com/kubernetes/enhancements/blob/master/keps/sig-api-machinery/3352-aggregated-discovery/README.md
836	  try {
837	    const aggregatedResp = await fetch('/api/kubernetes/apis', {
838	      headers: {
839	        Accept: 'application/json;g=apidiscovery.k8s.io;v=v2;as=APIGroupDiscoveryList',
840	      },
841	    });
842	    if (!aggregatedResp.ok) {
843	      throw new Error(`Error fetching aggregated discovery: ${aggregatedResp.statusText}`);
844	    }
845	    const aggregatedData = await aggregatedResp.json();
846	    if (Array.isArray(aggregatedData.items)) {
847	      aggregatedData.items.forEach((groupItem: any) => {
848	        const groupName = groupItem.metadata?.name;
849	        if (groupItem.versions && Array.isArray(groupItem.versions)) {
850	          groupItem.versions.forEach((versionData: any) => {
851	            const version = versionData.version;
852	            if (versionData.resources && Array.isArray(versionData.resources)) {
853	              versionData.resources.forEach((resource: any) => {
854	                const kind = resource.responseKind?.kind || resource.kind;
855	                const resourceName = resource.resource || resource.name;
856	                if (kind && resourceName && !resourceName.includes('/')) {
857	                  updateMapping(kind, groupName, version);
858	                }
859	              });
860	            }
861	          });
862	        }
863	      });
864	    }
865	  } catch (error) {
866	    console.error('Error fetching aggregated API discovery data:', error);
867	  }
868	
869	  return mapping;
870	};
871	
872	export default PolicyTopologyPage;

