 57	
 58	interface GVK {
 59	  group: string;
 60	  version: string;
 61	  kind: string;
 62	}
 63	let dynamicResourceGVKMapping: Record<string, GVK> = {};
 64	const resourceHints: Record<string, string> = {
 65	  Gateway: 'gateway.networking.k8s.io',
 66	  DNSRecord: 'kuadrant.io',
 67	};
 68	
 69	// Fetch the config.js file dynamically at runtime
 70	// Normally served from <cluster-host>/api/plugins/kuadrant-console/config.js
 71	const fetchConfig = async () => {
 72	  const defaultConfig = {
 73	    TOPOLOGY_CONFIGMAP_NAME: 'topology',
 74	    TOPOLOGY_CONFIGMAP_NAMESPACE: 'kuadrant-system',
 75	  };
 76	
 77	  try {
 78	    const response = await fetch('/api/plugins/kuadrant-console-plugin/config.js');
 79	    if (!response.ok) {
 80	      if (response.status === 404) {
 81	        console.warn('config.js not found (running locally perhaps). Falling back to defaults.');
 82	      } else {
 83	        throw new Error(`Failed to fetch config.js: ${response.statusText}`);
 84	      }
 85	      return defaultConfig; // Fallback on 404
 86	    }
 87	
 88	    const script = await response.text();
 89	
 90	    const configScript = document.createElement('script');
 91	    configScript.innerHTML = script;
 92	    document.head.appendChild(configScript);
 93	
 94	    return (window as any).kuadrant_config || defaultConfig;
 95	  } catch (error) {
 96	    console.error('Error loading config.js:', error);
 97	    return defaultConfig;
 98	  }
 99	};
100	
101	export const kindToAbbr = (kind: string) => {
102	  return (kind.replace(/[^A-Z]/g, '') || kind.toUpperCase()).slice(0, 4);
103	};
104	
