123	// Convert DOT graph to PatternFly node/edge models
124	const parseDotToModel = (dotString: string): { nodes: any[]; edges: any[] } => {
125	  try {
126	    const graph = dot.read(dotString);
127	    const nodes: any[] = [];
128	    const edges: any[] = [];
129	    const groups: any[] = [];
130	    const connectedNodeIds = new Set<string>();
131	
132	    const shapeMapping: { [key: string]: NodeShape } = {
133	      Gateway: NodeShape.rect,
134	      HTTPRoute: NodeShape.rect,
135	      TLSPolicy: NodeShape.rect,
136	      DNSPolicy: NodeShape.rect,
137	      AuthPolicy: NodeShape.rect,
138	      RateLimitPolicy: NodeShape.rect,
139	      ConfigMap: NodeShape.ellipse,
140	      Listener: NodeShape.rect,
141	      Kuadrant: NodeShape.ellipse,
142	    };
143	
144	    // kinds for unassociated policies - these will be grouped
145	    const unassociatedPolicies = new Set([
146	      'TLSPolicy',
147	      'DNSPolicy',
148	      'AuthPolicy',
149	      'RateLimitPolicy',
150	    ]);
151	
152	    // kinds for Kuadrant internals - these will be grouped also
153	    const kuadrantInternals = new Set([
154	      'ConfigMap',
155	      'Kuadrant',
156	      'Limitador',
157	      'Authorino',
158	      'ConsolePlugin',
159	    ]);
160	
161	    const addEdge = (source: string, target: string, type: string) => {
162	      edges.push({
163	        id: `edge-${source}-${target}`,
164	        type: 'edge',
165	        source,
166	        target,
167	        edgeStyle: type === 'policy' ? EdgeStyle.dashedMd : EdgeStyle.default,
168	        animationSpeed: type === 'policy' ? EdgeAnimationSpeed.medium : undefined,
169	        style: { strokeWidth: 2, stroke: '#393F44' },
170	      });
171	      connectedNodeIds.add(source);
172	      connectedNodeIds.add(target);
173	    };
174	
175	    // process edges: add each edge directly
176	    graph
177	      .edges()
178	      .forEach(({ v: sourceNodeId, w: targetNodeId }: { v: string; w: string }) =>
179	        addEdge(sourceNodeId, targetNodeId, 'default'),
180	      );
181	
182	    // create nodes
183	    graph.nodes().forEach((nodeId: string) => {
184	      const nodeData = graph.node(nodeId);
185	      const [resourceType, resourceName] = nodeData.label.split('\\n');
186	      nodes.push({
187	        id: nodeId,
188	        type: 'node',
189	        label: resourceName,
190	        resourceType,
191	        width: 120,
192	        height: 65,
193	        labelPosition: LabelPosition.bottom,
194	        shape: shapeMapping[resourceType] || NodeShape.rect,
195	        data: {
196	          label: resourceName,
197	          type: resourceType,
198	          badge: kindToAbbr(resourceType),
199	          badgeColor: '#2b9af3',
200	        },
201	      });
202	    });
203	
204	    const addGroup = (id: string, children: any[], label: string) => {
205	      groups.push({
206	        id,
207	        children: children.map((node) => node.id),
208	        type: 'group',
209	        group: true,
210	        label,
211	        style: { padding: 40 },
212	      });
213	    };
214	
215	    // Group unassociated policies
216	    const unassociatedPolicyNodes = nodes.filter(
217	      (node) => !connectedNodeIds.has(node.id) && unassociatedPolicies.has(node.resourceType),
218	    );
219	    if (unassociatedPolicyNodes.length) {
220	      addGroup('group-unattached', unassociatedPolicyNodes, 'Unattached Policies');
221	    }
222	
223	    // Group Kuadrant internals
224	    const kuadrantInternalNodes = nodes.filter((node) => kuadrantInternals.has(node.resourceType));
225	    if (kuadrantInternalNodes.length) {
226	      addGroup('group-kuadrant-internals', kuadrantInternalNodes, 'Kuadrant Internals');
227	    }
228	
229	    // Filter out any remaining edges with missing nodes
230	    const nodeIds = new Set(nodes.map((node) => node.id));
231	    const validEdges = edges.filter(
232	      ({ source, target }) => nodeIds.has(source) && nodeIds.has(target),
233	    );
234	
235	    return { nodes: [...nodes, ...groups], edges: validEdges };
236	  } catch (error) {
237	    console.error('Error parsing DOT string:', error);
238	    throw error;
239	  }
