585	          const validNodeIds = new Set(finalNodes.map((n) => n.id));
586	          const filteredEdges = edges.filter(
587	            (e) => validNodeIds.has(e.source) && validNodeIds.has(e.target),
588	          );
589	
590	          if (controllerRef.current) {
591	            const newModel = {
592	              nodes: finalNodes,
593	              edges: filteredEdges,
594	              graph: {
595	                id: 'g1',
596	                type: 'graph',
597	                layout: 'Dagre',
598	              },
599	            };
600	
601	            controllerRef.current.fromModel(newModel, false);
602	            controllerRef.current.getGraph().layout();
603	            controllerRef.current.getGraph().fit(80);
604	          }
605	        } catch (error) {
606	          setParseError('Failed to parse topology data.');
607	          console.error(error, dotString);
608	        }
609	      }
610	    } else if (loadError) {
611	      setParseError('Failed to load topology data.');
612	    }
613	  }, [configMap, loaded, loadError, selectedResourceTypes]);
